INSERT INTO COMTNEXPENSEMANAGE
	   (CNSLT_ID
	  , CNSLT_SJ
	  , CNSLT_CN
	  , OTHBC_AT
	  , WRITNG_PASSWORD
	  , AREA_NO
	  , MIDDLE_TELNO
	  , END_TELNO
	  , FRST_MBTLNUM
	  , MIDDLE_MBTLNUM
	  , END_MBTLNUM
	  , EMAIL_ADRES
	  , EMAIL_ANSWER_AT
	  , MBER_NM
	  , WRITNG_DE
	  , RDCNT
	  , CATEGORY_ID
	  , ATCH_FILE_ID
	  , FRST_REGIST_PNTTM
	  , FRST_REGISTER_ID)
VALUES ( #{expenseId}
