	  , #{endMbtlnum}
	  , #{emailAdres}
	  , #{emailAnswerAt}
	  , #{wrterNm}
	  , DATE_FORMAT(SYSDATE(), 'YYYYMMDD')
	  , 0
	  , '1'
	  , #{atchFileId}
	  , SYSDATE()
	  , #{frstRegisterId})

