UPDATE	COMTNEXPENSEMANAGE	SET
	    CNSLT_SJ=#{cnsltSj}
	  , CNSLT_CN=#{cnsltCn}
	  , OTHBC_AT=#{othbcAt}
	  , WRITNG_PASSWORD=#{writngPassword}
	  , AREA_NO=#{areaNo}
	  , MIDDLE_TELNO=#{middleTelno}
	  , END_TELNO=#{endTelno}
	  , FRST_MBTLNUM=#{firstMoblphonNo}
	  , MIDDLE_MBTLNUM=#{middleMbtlnum}
	  , END_MBTLNUM=#{endMbtlnum}
	  , EMAIL_ADRES=#{emailAdres}
	  , EMAIL_ANSWER_AT=IFNULL(#{emailAnswerAt},'N')
	  , MBER_NM=#{wrterNm}
	  , WRITNG_DE=DATE_FORMAT(SYSDATE(), 'YYYYMMDD')
	  , MANAGT_CN=#{managtCn}
	  , MANAGT_DE=#{managtDe}
	  , ATCH_FILE_ID=#{atchFileId}
	  , FRST_REGIST_PNTTM=SYSDATE()
	  , FRST_REGISTER_ID=#{frstRegisterId}
WHERE  CNSLT_ID=#{expenseId}


UPDATE	COMTNEXPENSEMANAGE	SET
	  	CATEGORY_ID=#{qnaProcessSttusCode}
	  , MANAGT_CN=#{managtCn}
	  , MANAGT_DE=DATE_FORMAT(SYSDATE(), 'YYYYMMDD')
	  , LAST_UPDT_PNTTM=SYSDATE()
	  , LAST_UPDUSR_ID=#{lastUpdusrId}
WHERE  CNSLT_ID=#{expenseId}
